import socket
import json

class GameServer:
    def __init__(self, host='0.0.0.0', port=9876):
        self.server_address = (host, port)
        self.players = ["Player1", "Player2", "Player3"]  # Example player list
        self.game_state = "Running"  # Example game state

    def get_status(self):
        status = {
            "players": self.players,
            "game_state": self.game_state
        }
        return json.dumps(status)

    def start_server(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.bind(self.server_address)

        print("Game server started, waiting for status queries...")
        while True:
            data, address = sock.recvfrom(4096)
            if data.decode() == 'status':
                response = self.get_status().encode()
                sock.sendto(response, address)

if __name__ == '__main__':
    server = GameServer()
    server.start_server()